    // Card Heroes
    public static void ApplyPowerStats(this CardHeroes cardHero, PowerManager powerManager)
    {
        if (powerManager == null) return;
        cardHero.Health = cardHero.Health + powerManager.Health + cardHero.BaseStats.Health * powerManager.PercentAllHealth / 100;
        cardHero.PhysicalAttack = cardHero.PhysicalAttack + powerManager.PhysicalAttack + cardHero.BaseStats.PhysicalAttack * powerManager.PercentAllPhysicalAttack / 100;
        cardHero.PhysicalDefense = cardHero.PhysicalDefense + powerManager.PhysicalDefense + cardHero.BaseStats.PhysicalDefense * powerManager.PercentAllPhysicalDefense / 100;
        cardHero.MagicalAttack = cardHero.MagicalAttack + powerManager.MagicalAttack + cardHero.BaseStats.MagicalAttack * powerManager.PercentAllMagicalAttack / 100;
        cardHero.MagicalDefense = cardHero.MagicalDefense + powerManager.MagicalDefense + cardHero.BaseStats.MagicalDefense * powerManager.PercentAllMagicalDefense / 100;
        cardHero.ChemicalAttack = cardHero.ChemicalAttack + powerManager.ChemicalAttack + cardHero.BaseStats.ChemicalAttack * powerManager.PercentAllChemicalAttack / 100;
        cardHero.ChemicalDefense = cardHero.ChemicalDefense + powerManager.ChemicalDefense + cardHero.BaseStats.ChemicalDefense * powerManager.PercentAllChemicalDefense / 100;
        cardHero.AtomicAttack = cardHero.AtomicAttack + powerManager.AtomicAttack + cardHero.BaseStats.AtomicAttack * powerManager.PercentAllAtomicAttack / 100;
        cardHero.AtomicDefense = cardHero.AtomicDefense + powerManager.AtomicDefense + cardHero.BaseStats.AtomicDefense * powerManager.PercentAllAtomicDefense / 100;
