        cardHero.MentalDefense = cardHero.MentalDefense + powerManager.MentalDefense + cardHero.BaseStats.MentalDefense * powerManager.PercentAllMentalDefense / 100;
        cardHero.Speed = cardHero.Speed + powerManager.Speed;
        cardHero.CriticalDamageRate = cardHero.CriticalDamageRate + powerManager.CriticalDamageRate;
        cardHero.CriticalRate = cardHero.CriticalRate + powerManager.CriticalRate;
        cardHero.CriticalResistanceRate = cardHero.CriticalResistanceRate + powerManager.CriticalResistanceRate;
        cardHero.IgnoreCriticalRate = cardHero.IgnoreCriticalRate + powerManager.IgnoreCriticalRate;
        cardHero.PenetrationRate = cardHero.PenetrationRate + powerManager.PenetrationRate;
        cardHero.PenetrationResistanceRate = cardHero.PenetrationResistanceRate + powerManager.PenetrationResistanceRate;
