    public static void ApplyPowerStats(this CardAdmirals cardAdmiral, PowerManager powerManager)
    {
        if (powerManager == null) return;
        cardAdmiral.Health = cardAdmiral.Health + powerManager.Health + cardAdmiral.BaseStats.Health * powerManager.PercentAllHealth / 100;
