    public static void RecalculatePower(this CardMilitaries cardMilitary)
    {
        cardMilitary.Power = PowerHelper.CalculatePower(
            cardMilitary.Health,
            cardMilitary.PhysicalAttack, cardMilitary.PhysicalDefense,
            cardMilitary.MagicalAttack, cardMilitary.MagicalDefense,
            cardMilitary.ChemicalAttack, cardMilitary.ChemicalDefense,
            cardMilitary.AtomicAttack, cardMilitary.AtomicDefense,
            cardMilitary.MentalAttack, cardMilitary.MentalDefense,
            cardMilitary.Speed,
            cardMilitary.CriticalDamageRate, cardMilitary.CriticalRate, cardMilitary.CriticalResistanceRate, cardMilitary.IgnoreCriticalRate,
            cardMilitary.PenetrationRate, cardMilitary.PenetrationResistanceRate, cardMilitary.EvasionRate,
            cardMilitary.DamageAbsorptionRate, cardMilitary.IgnoreDamageAbsorptionRate, cardMilitary.AbsorbedDamageRate,
            cardMilitary.VitalityRegenerationRate, cardMilitary.VitalityRegenerationResistanceRate,
            cardMilitary.AccuracyRate, cardMilitary.LifestealRate,
            cardMilitary.ShieldStrength, cardMilitary.Tenacity, cardMilitary.ResistanceRate,
            cardMilitary.ComboRate, cardMilitary.IgnoreComboRate, cardMilitary.ComboDamageRate, cardMilitary.ComboResistanceRate,
            cardMilitary.StunRate, cardMilitary.IgnoreStunRate,
            cardMilitary.ReflectionRate, cardMilitary.IgnoreReflectionRate, cardMilitary.ReflectionDamageRate, cardMilitary.ReflectionResistanceRate,
            cardMilitary.Mana, cardMilitary.ManaRegenerationRate,
            cardMilitary.DamageToDifferentFactionRate, cardMilitary.ResistanceToDifferentFactionRate,
            cardMilitary.DamageToSameFactionRate, cardMilitary.ResistanceToSameFactionRate,
            cardMilitary.NormalDamageRate, cardMilitary.NormalResistanceRate,
            cardMilitary.SkillDamageRate, cardMilitary.SkillResistanceRate
        );
    }
